2815→// StartGitHubSyncWorker starts a background goroutine that runs auto-sync
2816→// every 15 minutes for projects with github_sync_interval set.
2817→func (s *Server) StartGitHubSyncWorker(ctx context.Context) {
2818→	ticker := time.NewTicker(15 * time.Minute)
2819→	defer ticker.Stop()
2820→	for {
2821→		select {
2822→		case <-ctx.Done():
2823→			return
2824→		case <-ticker.C:
2825→			s.runAutoSync(ctx)
2826→		}
2827→	}
2828→}
