2842→func (s *Server) runAutoSync(ctx context.Context) {
2843→	rows, err := s.db.QueryContext(ctx, `
2844→		SELECT id, COALESCE(github_owner,''), COALESCE(github_repo_name,''),
2845→		       COALESCE(github_token,''), COALESCE(github_project_url,''),
2846→		       github_sync_interval, COALESCE(github_sync_hour,0), COALESCE(github_sync_day,0),
2847→		       github_last_sync
2848→		FROM projects
2849→		WHERE github_sync_enabled = true
2850→		  AND github_sync_interval IS NOT NULL
2851→		  AND github_token IS NOT NULL
2852→	`)
2853→	if err != nil {
2854→		s.logger.Error("auto-sync: failed to query projects", zap.Error(err))
2855→		return
2856→	}
2857→	defer rows.Close()
2858→
2859→	var projects []autoSyncProject
2860→	for rows.Next() {
2861→		var p autoSyncProject
2862→		if err := rows.Scan(&p.ID, &p.Owner, &p.Repo, &p.Token, &p.ProjectURL, &p.SyncInterval, &p.SyncHour, &p.SyncDay, &p.LastSync); err != nil {
2863→			continue
2864→		}
2865→		projects = append(projects, p)
2866→	}
2867→	rows.Close()
2868→
2869→	now := time.Now()
2870→	for _, p := range projects {
2871→		if !shouldSync(p.SyncInterval, p.SyncHour, p.SyncDay, p.LastSync, now) {
2872→			continue
2873→		}
2874→		proj := p // capture
2875→		go func() {
2876→			syncCtx, cancel := context.WithTimeout(context.Background(), 10*time.Minute)
2877→			defer cancel()
2878→
2879→			req, err := s.loadSavedGitHubMappingsForAutoSync(syncCtx, int64(proj.ID))
2880→			if err != nil {
2881→				s.logger.Warn("auto-sync: failed to load mappings", zap.Int("project_id", proj.ID), zap.Error(err))
2882→				return
2883→			}
2884→			req.PullTasks = true
2885→			req.PullComments = true
2886→
2887→			s.runGitHubImportCore(syncCtx, proj.ID, proj.Owner, proj.Repo, proj.Token, proj.ProjectURL, req, "auto")
2888→		}()
2889→	}
2890→}
