226→func fetchGitHubJSON(ctx context.Context, token, url string, dest interface{}) error {
227→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
228→	if err != nil {
229→		return err
230→	}
231→	req.Header.Set("Accept", "application/vnd.github+json")
232→	req.Header.Set("X-GitHub-Api-Version", "2022-11-28")
233→	if token != "" {
234→		req.Header.Set("Authorization", "Bearer "+token)
235→	}
236→
237→	resp, err := http.DefaultClient.Do(req)
238→	if err != nil {
239→		return err
240→	}
241→	defer resp.Body.Close()
242→
243→	if resp.StatusCode >= 400 {
244→		body, _ := io.ReadAll(resp.Body)
245→		return fmt.Errorf("github api error %d: %s", resp.StatusCode, strings.TrimSpace(string(body)))
246→	}
247→
248→	return json.NewDecoder(resp.Body).Decode(dest)
249→}
