251→// fetchGitHubGraphQL sends a GraphQL query to the GitHub API.
252→func fetchGitHubGraphQL(ctx context.Context, token, query string, variables map[string]interface{}, dest interface{}) error {
253→	payload := map[string]interface{}{"query": query}
254→	if variables != nil {
255→		payload["variables"] = variables
256→	}
257→	body, err := json.Marshal(payload)
258→	if err != nil {
259→		return err
260→	}
261→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, "https://api.github.com/graphql", bytes.NewReader(body))
262→	if err != nil {
263→		return err
264→	}
265→	req.Header.Set("Content-Type", "application/json")
266→	req.Header.Set("Authorization", "Bearer "+token)
267→	req.Header.Set("X-GitHub-Api-Version", "2022-11-28")
268→
269→	resp, err := http.DefaultClient.Do(req)
270→	if err != nil {
271→		return err
272→	}
273→	defer resp.Body.Close()
274→
275→	if resp.StatusCode >= 400 {
276→		b, _ := io.ReadAll(resp.Body)
277→		return fmt.Errorf("github graphql error %d: %s", resp.StatusCode, strings.TrimSpace(string(b)))
278→	}
279→	return json.NewDecoder(resp.Body).Decode(dest)
280→}
