283→// Checks both repo-linked projects AND owner-level projects (user or org).
284→// Returns project info (id, status field id, options) from the first project found, or nil if none.
285→func fetchProjectStatusColumns(ctx context.Context, token, owner, repo string) (*ghProjectInfo, error) {
286→	if token == "" {
287→		return nil, nil
288→	}
289→	// Query both repo-linked projects and owner-level projects (handles org and user owners)
290→	const q = `
291→query($owner: String!, $repo: String!) {
292→  repository(owner: $owner, name: $repo) {
293→    projectsV2(first: 50) {
294→      nodes {
295→        id
296→        fields(first: 20) {
297→          nodes {
298→            ... on ProjectV2SingleSelectField { id name options { id name } }
299→          }
300→        }
301→      }
302→    }
303→    owner {
304→      ... on Organization {
305→        projectsV2(first: 50) {
306→          nodes {
307→            id
308→            fields(first: 20) {
309→              nodes {
310→                ... on ProjectV2SingleSelectField { id name options { id name } }
311→              }
312→            }
313→          }
314→        }
315→      }
316→      ... on User {
317→        projectsV2(first: 50) {
318→          nodes {
319→            id
320→            fields(first: 20) {
321→              nodes {
322→                ... on ProjectV2SingleSelectField { id name options { id name } }
323→              }
324→            }
325→          }
326→        }
327→      }
328→    }
329→  }
330→}`
331→	var result struct {
332→		Data struct {
333→			Repository struct {
334→				ProjectsV2 struct {
335→					Nodes []ghProjectV2 `json:"nodes"`
336→				} `json:"projectsV2"`
337→				Owner struct {
338→					ProjectsV2 struct {
339→						Nodes []ghProjectV2 `json:"nodes"`
340→					} `json:"projectsV2"`
341→				} `json:"owner"`
342→			} `json:"repository"`
343→		} `json:"data"`
344→		Errors []struct {
