346→		} `json:"errors"`
347→	}
348→	if err := fetchGitHubGraphQL(ctx, token, q, map[string]interface{}{"owner": owner, "repo": repo}, &result); err != nil {
349→		return nil, err
350→	}
351→	if len(result.Errors) > 0 {
352→		return nil, fmt.Errorf("graphql: %s", result.Errors[0].Message)
353→	}
354→
355→	// Combine repo-linked and owner-level projects, deduplicated by project ID
356→	seen := map[string]bool{}
357→	var allProjects []ghProjectV2
358→	for _, p := range result.Data.Repository.ProjectsV2.Nodes {
359→		if !seen[p.ID] {
