369→	}
370→
371→	for _, proj := range allProjects {
372→		// Prefer a field named after common status names, fall back to first single-select field
373→		var best *ghProjectField
374→		for i := range proj.Fields.Nodes {
375→			f := &proj.Fields.Nodes[i]
376→			if len(f.Options) == 0 {
377→				continue
378→			}
379→			lower := strings.ToLower(f.Name)
380→			if strings.Contains(lower, "status") || strings.Contains(lower, "stage") ||
381→				strings.Contains(lower, "state") || strings.Contains(lower, "phase") ||
382→				strings.Contains(lower, "column") {
383→				best = f
384→				break
385→			}
386→			if best == nil {
387→				best = f
388→			}
389→		}
390→		if best != nil {
391→			return &ghProjectInfo{
392→				ProjectID: proj.ID,
393→				FieldID:   best.ID,
394→				Options:   best.Options,
395→			}, nil
396→		}
397→	}
