2764→// shouldSync returns true if an auto-sync is due based on interval, hour, day and last sync time.
2765→func shouldSync(interval string, hour, day int, lastSync sql.NullTime, now time.Time) bool {
2766→	if !lastSync.Valid {
2767→		return true // never synced → fire immediately
2768→	}
2769→	scheduled := scheduledWindowStart(interval, hour, day, now)
2770→	if scheduled.IsZero() {
2771→		return false
2772→	}
2773→	return lastSync.Time.Before(scheduled)
2774→}
