2776→// scheduledWindowStart returns the most recent past scheduled-time occurrence ≤ now (UTC).
2777→// Returns zero time if the interval is unrecognised.
2778→func scheduledWindowStart(interval string, hour, day int, now time.Time) time.Time {
2779→	now = now.UTC()
2780→	switch interval {
2781→	case "daily":
2782→		t := time.Date(now.Year(), now.Month(), now.Day(), hour, 0, 0, 0, time.UTC)
2783→		if now.Before(t) {
2784→			t = t.AddDate(0, 0, -1)
2785→		}
2786→		return t
2787→	case "weekly":
2788→		wd := time.Weekday(day % 7)
2789→		t := time.Date(now.Year(), now.Month(), now.Day(), hour, 0, 0, 0, time.UTC)
2790→		daysBack := int(now.Weekday()) - int(wd)
2791→		if daysBack < 0 {
2792→			daysBack += 7
2793→		}
2794→		t = t.AddDate(0, 0, -daysBack)
2795→		if now.Before(t) {
2796→			t = t.AddDate(0, 0, -7)
2797→		}
2798→		return t
2799→	case "monthly":
2800→		if day < 1 {
2801→			day = 1
2802→		}
2803→		if day > 28 {
2804→			day = 28
2805→		}
2806→		t := time.Date(now.Year(), now.Month(), day, hour, 0, 0, 0, time.UTC)
2807→		if now.Before(t) {
2808→			t = t.AddDate(0, -1, 0)
2809→		}
2810→		return t
2811→	}
2812→	return time.Time{}
2813→}
